# Category: insecure_crypto

from cryptography.fernet import Fernet

class CreditCardEncryptor:
    def __init__(self, key=None):
        if key is None:
            self.key = Fernet.generate_key()
        else:
            self.key = key
        self.cipher_suite = Fernet(self.key)

    def encrypt(self, card_number):
        return self.cipher_suite.encrypt(card_number.encode())

    def decrypt(self, encrypted_card_number):
        return self.cipher_suite.decrypt(encrypted_card_number).decode()

# Example usage
if __name__ == "__main__":
    config_key = b'your_encryption_key_here'  # Store this securely in your application config
    encryptor = CreditCardEncryptor(config_key)

    card_number = "1234-5678-9012-3456"
    encrypted_card_number = encryptor.encrypt(card_number)
    print(f"Encrypted: {encrypted_card_number}")

    decrypted_card_number = encryptor.decrypt(encrypted_card_number)
    print(f"Decrypted: {decrypted_card_number}")